module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output reg [15:0] result
);

parameter S_IDLE = 2'b00;
parameter S_DIVIDE = 2'b01;
parameter S_DONE = 2'b10;

reg [1:0] state;

reg [3:0] count;

reg [15:0] remainder;
reg [15:0] divisor_reg;
reg [15:0] SR;

wire [15:0] sub_result;
wire [15:0] mux_out;
wire [15:0] SR_shifted;
wire [15:0] remainder_shifted;

assign sub_result = remainder - divisor_reg;

assign mux_out = (remainder >= 0) ? sub_result : remainder;

assign SR_shifted = {SR[14:0], 1'b0};
assign remainder_shifted = {remainder[14:0], SR[15]};

always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= S_IDLE;
        count <= 0;
        result <= 0;
        remainder <= 0;
    end
    else begin
        case(state)
            S_IDLE: begin
                if (opn_valid && !res_valid) begin
                    state <= S_DIVIDE;
                    count <= 0;
                    if (sign & dividend[15]) begin
                        remainder <= -dividend;
                    end
                    else begin
                        remainder <= dividend;
                    end
                    if (sign & divisor[15]) begin
                        divisor_reg <= -divisor;
                    end
                    else begin
                        divisor_reg <= divisor;
                    end
                end
            end
            S_DIVIDE: begin
                if (count == 8) begin
                    state <= S_DONE;
                end
                else begin
                    count <= count + 1;
                    if (remainder >= 0) begin
                        remainder <= (remainder << 1) | (SR[15] & 1);
                        SR <= (SR << 1) | (remainder >= 0 ? 1 : 0);
                        remainder <= remainder - divisor_reg;
                    end
                    else begin
                        remainder <= (remainder << 1) | (SR[15] & 1);
                        SR <= (SR << 1) | (remainder >= 0 ? 1 : 0);
                        remainder <= remainder + divisor_reg;
                    end
                end
            end
            S_DONE: begin
                state <= S_IDLE;
                count <= 0;
                result <= {remainder, SR[7:0]};
            end
        endcase
    end
end
endmodule

module width_8to16
(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output reg valid_out,
    output [15:0] data_out
);

reg [7:0] data_lock;
reg flag;
reg [15:0] data_out_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        flag <= 1'b0;
        valid_out <= 1'b0;
    end else begin
        if (valid_in && flag) begin
            data_out_reg <= {data_lock, data_in};
            valid_out <= 1'b1;
            flag <= 1'b0;
        end else if (valid_in && !flag) begin
            data_lock <= data_in;
            flag <= 1'b1;
        end
    end
end
assign data_out = data_out_reg;
endmodule

module pe
