    input [31:0] b,
    output [31:0] c
);

    reg [31:0] c_reg;

    wire [31:0] mult;

    assign mult = a * b;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            c_reg <= 32'd0;
        end else begin
            c_reg <= c_reg + mult;
        end
    end

    assign c = c_reg;
endmodule

