module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

    reg [4:0] i;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) i <= 5'd0;
        else if (start && i < 5'd17) i <= i + 1'd1;
        else if (!start) i <= 5'd0;
    end

    reg done_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) done_r <= 1'd0;
        else if (i == 5'd16) done_r <= 1'd1;
        else if (i == 5'd17) done_r <= 1'd0;
    end

    reg [15:0] areg;
    reg [15:0] breg;
    reg [31:0] yout_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            areg <= 16'd0;
            breg <= 16'd0;
            yout_r <= 32'd0;
        end else if (start) begin
            areg <= ain;
            breg <= bin;
            yout_r <= i == 5'd0 ? 32'd0 :
                      i == 5'd1 ? (areg[0] ? {16'd0, breg} : 32'd0) :
                      i < 5'd17 && areg[i-1] ? yout_r + (breg << (i-1)) : 32'd0;
        end
    end

    assign yout = yout_r;
    assign done = done_r;

endmodule

module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
    parameter MUL_WIDTH = 8;

    reg mul_en_out_reg[0:MUL_WIDTH-1];
    reg [MUL_WIDTH-1:0] mul_a_reg;
    reg [MUL_WIDTH-1:0] mul_b_reg;
    reg [2*MUL_WIDTH-1:0] mul_out_reg;

    always @(posedge clk) begin
        if (!rst_n) begin
            mul_en_out_reg[0] <= 1'b0;
            mul_a_reg <= {MUL_WIDTH{1'b0}};
            mul_b_reg <= {MUL_WIDTH{1'b0}};
        end else begin
            mul_en_out_reg[0] <= mul_en_in;
            if (mul_en_in) begin
                mul_a_reg <= mul_a;
                mul_b_reg <= mul_b;
            end
        end
    end

    wire [MUL_WIDTH-1:0] temp[0:MUL_WIDTH-1];
    genvar i;
    generate
        for (i = 0; i < MUL_WIDTH; i = i + 1) begin: gen_partial_products
            assign temp[i] = mul_a_reg & {MUL_WIDTH{mul_b_reg[i]}};
        end
    endgenerate

    reg [2*MUL_WIDTH-1:0] sum[0:MUL_WIDTH-1];
    genvar j;
    generate
        for (j = 0; j < MUL_WIDTH-1; j = j + 1) begin: add_partial_products
            always @(posedge clk) begin
                if (mul_en_in) begin
                    sum[j+1] <= sum[j] + temp[j];
                end
            end
        end
    endgenerate

    always @(posedge clk) begin
        if (mul_en_in) begin
            mul_out_reg <= sum[MUL_WIDTH-1] + temp[MUL_WIDTH-1];
        end
    end

    assign mul_en_out = mul_en_out_reg[MUL_WIDTH-1];
    assign mul_out = mul_en_out ? mul_out_reg : 0;
endmodule

