module div_16bit
(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    integer i;

    always @(A, B) begin
        dividend <= A;
        divisor <= B;
    end

    always @(dividend, divisor) begin
        result = 0;
        remainder = 0;

        for (i = 15; i >= 8; i = i - 1) begin
            remainder = {remainder[14:0], dividend[i]};
            if (remainder >= divisor) begin
                remainder = remainder - divisor;
                result[i] = 1'b1;
            end
            else begin
                result[i] = 1'b0;
            end
        end

        odd = remainder;
    end
endmodule

module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    reg [7:0] multiplier;
    reg [3:0] shift_count;

    always @(*) begin
        partial_product = 16'b0;
        multiplier = B;
        shift_count = 4'b0;

        while (shift_count < 8) begin
            if (multiplier[0] == 1'b1) begin
                partial_product = partial_product + (A << shift_count);
            end
            multiplier = multiplier >> 1;
            shift_count = shift_count + 1;
        end

        product = partial_product;
    end

endmodule

module freq_div
(
