    if (RST) begin
        CLK_50 <= 1'b0;
        CLK_10 <= 1'b0;
        CLK_1 <= 1'b0;
        cnt_10 <= 4'b0;
        cnt_100 <= 7'b0;
    end
    else begin

        CLK_50 <= ~CLK_50;

        if (cnt_10 == 4'd4) begin
            CLK_10 <= ~CLK_10;
            cnt_10 <= 4'b0;
        end
        else begin
            cnt_10 <= cnt_10 + 4'b1;
        end

        if (cnt_100 == 7'd49) begin
            CLK_1 <= ~CLK_1;
            cnt_100 <= 7'b0;
        end
        else begin
            cnt_100 <= cnt_100 + 7'b1;
        end
    end
end
endmodule

module alu
(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;
    wire signed [31:0] a_signed = a;
    wire signed [31:0] b_signed = b;
    reg [31:0] res;
    reg [31:0] res_signed;
    assign r = res;
    assign zero = res == 0;
    assign carry = res[32];
    assign negative = res_signed[31];
    assign overflow = res_signed[31] ^ res_signed[30];
    assign flag = res_signed[31];
    always @(*) begin
        case (aluc)
            ADD: res = a_signed + b_signed;
            ADDU: res = a + b;
            SUB: res = a_signed - b_signed;
            SUBU: res = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = a_signed < b_signed;
            SLTU: res = a < b;
            SLL: res = b << a[4:0];
            SRL: res = b >> a[4:0];
            SRA: res = b_signed >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = b_signed >>> a[4:0];
            LUI: res = {b[15:0], 16'b0};
            default: res = 0;
        endcase
    end
endmodule

module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);
    reg a_d;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            a_d <= 1'b0;
        else
            a_d <= a;
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rise <= 1'b0;
            down <= 1'b0;
        end else begin
            if (a_d == 1'b0 && a == 1'b1)
                rise <= 1'b1;
            else
                rise <= 1'b0;
            if (a_d == 1'b1 && a == 1'b0)
                down <= 1'b1;
            else
                down <= 1'b0;
        end
    end
endmodule

