module pulse_detect
(
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);
reg [1:0] state;
parameter IDLE = 2'b00, PULSE_START = 2'b01, PULSE_END = 2'b10;
always @(posedge clk, negedge rst_n) begin
    if (~rst_n) begin
        state <= IDLE;
        data_out <= 1'b0;
    end
    else begin
        case (state)
            IDLE: begin
                if (data_in) begin
                    state <= PULSE_START;
                end
                else begin
                    state <= IDLE;
                end
                data_out <= 1'b0;
            end
            PULSE_START: begin
                if (data_in) begin
                    state <= PULSE_END;
                end
                else begin
                    state <= IDLE;
                end
                data_out <= 1'b0;
            end
            PULSE_END: begin
                if (data_in) begin
                    state <= PULSE_END;
                end
                else begin
                    state <= IDLE;
                end
                data_out <= 1'b1;
            end
            default: begin
                state <= IDLE;
                data_out <= 1'b0;
            end
        endcase
    end
end
endmodule

module adder_8bit
(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);

    assign {cout, sum} = a + b + cin;
endmodule

module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

reg [9:0] sum;
reg [1:0] count;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        sum <= 10'b0;
        count <= 2'b0;
        valid_out <= 1'b0;
    end
    else if (valid_in) begin
        sum <= sum + data_in;
        count <= count + 1'b1;
        if (count == 2'b11) begin
            valid_out <= 1'b1;
            data_out <= sum;
        end
        else begin
            valid_out <= 1'b0;
        end
    end
    else begin
        valid_out <= 1'b0;
    end
end

endmodule

module RAM
#(
    parameter WIDTH = 6,
    parameter DEPTH = 8
)
(
    input clk,
    input rst_n,
    input write_en,
    input [$clog2(DEPTH)-1:0] write_addr,
    input [WIDTH-1:0] write_data,
    input read_en,
    input [$clog2(DEPTH)-1:0] read_addr,
    output reg [WIDTH-1:0] read_data
);
parameter WIDTH = 6;
parameter DEPTH = 8;
reg [3:0] i;
task initialize_RAM;
    for (i = 0; i < DEPTH; i = i + 1) begin RAM[i] = 0; end
always @(*) begin
    if (!rst_n) begin
        read_data = 6'b000000;
    end else begin
        if (read_en) begin
            read_data = RAM[read_addr];
        end else begin
            RAM[write_addr] = write_data;
        end
    end
end
endmodule

module right_shifter
(
    input clk,
    input d,
    output reg q
);

    initial q = 8'b0; 
    always @(posedge clk) begin
        q <= (q >> 1); 
        q[7] <= d; 
    end
endmodule

module synchronizer
(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);

    reg [3:0] data_reg;
    reg en_data_reg;
    reg en_clap_one;
    reg en_clap_two;

    always @(posedge clk_a or negedge arstn) begin
        if (!arstn) begin
            data_reg <= 4'b0;
        end else begin
            data_reg <= data_in;
        end
    end

    always @(posedge clk_a or negedge arstn) begin
        if (!arstn) begin
            en_data_reg <= 1'b0;
        end else begin
            en_data_reg <= data_en;
        end
    end

    always @(posedge clk_b or negedge brstn) begin
        if (!brstn) begin
            en_clap_one <= 1'b0;
            en_clap_two <= 1'b0;
        end else begin
            en_clap_one <= en_data_reg;
            en_clap_two <= en_clap_one;
        end
    end

    always @(posedge clk_b or negedge brstn) begin
        if (!brstn) begin
            dataout <= 4'b0;
        end else begin
            if (en_clap_two) begin
                dataout <= data_reg;
            end else begin
                dataout <= dataout;
            end
        end
    end
endmodule
